    final l10n = context.l10n;
    final pitches = pitchFeatures.pitches;
    final getPitchTypeColor = usePitchTypeColor();
    final translatePitchType = useTranslatePitchType();
    final unitType = ref.watch(appUnitProvider);

    final vUnit = UnitConverter.formatVelocity(0, unitType).unit;
    final bUnit = UnitConverter.formatBreak(0, unitType).unit;

    final effectiveTitleStyle = titleStyle ??
        theme.textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.w600,
          color: scheme.onSurface,
        );
    final tableHeaderStyle = theme.textTheme.bodySmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.onSurfaceVariant,
    );
    final tableHeaderFontSize = tableHeaderStyle?.fontSize ?? 12;
    final tableUnitStyle = tableHeaderStyle?.copyWith(
      fontSize: tableHeaderFontSize - 1,
      fontWeight: FontWeight.w500,
      color: scheme.onSurfaceVariant.withValues(alpha: 0.7),
    );
    final tableValueStyle = theme.textTheme.bodyMedium?.copyWith(
      fontWeight: FontWeight.w500,
      color: scheme.onSurface,
    );
    final tablePitchNameStyle = theme.textTheme.bodySmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.onSurface,
    );
    final pitchNameStyle = theme.textTheme.titleSmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.onSurface,
    );
    final detailLabelStyle = theme.textTheme.bodyMedium?.copyWith(
      color: scheme.onSurfaceVariant,
    );

    return ExpansionTileCard(
      titleBuilder: (icon) => Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(
                l10n.ai_coach_report__pitch_features_title,
                style: effectiveTitleStyle,
              ),
              icon,
            ],
          ),
          const Gap(16),
          // 球種データテーブル（常時表示）
          Container(
            decoration: BoxDecoration(
              border: Border.all(color: scheme.outline.withValues(alpha: 0.3)),
              borderRadius: BorderRadius.circular(8),
            ),
            child: Column(
              children: [
                // ヘッダー行
                Container(
                  decoration: BoxDecoration(
                    color:
                        scheme.surfaceContainerHighest.withValues(alpha: 0.5),
                    borderRadius:
                        const BorderRadius.vertical(top: Radius.circular(7)),
                  ),
                  padding:
                      const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
                  child: Row(
                    children: [
                      Expanded(
                        flex: 2,
                        child: Text(
                          l10n.ai_coach_report__pitch_type_column,
                          style: tableHeaderStyle,
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__velocity_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$vUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__vertical_break_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$bUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                      Expanded(
                        flex: 1,
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.end,
                          children: [
                            Text(
                              l10n.ai_coach_report__horizontal_break_column,
                              style: tableHeaderStyle,
                            ),
                            Text(
                              '[$bUnit]',
                              style: tableUnitStyle,
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
                // データ行
                ...pitches.map((pitch) {
                  return Container(
                    decoration: BoxDecoration(
                      border: Border(
                        bottom: BorderSide(
                          color: scheme.outline.withValues(alpha: 0.2),
                          width: 0.5,
                        ),
                      ),
                    ),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 10,
                    ),
                    child: Row(
                      children: [
                        Expanded(
                          flex: 2,
                          child: Row(
                            children: [
                              Container(
                                width: 8,
                                height: 8,
                                decoration: BoxDecoration(
                                  color: getPitchTypeColor(
                                      pitch.pitchType.pitchType),
                                  shape: BoxShape.circle,
                                ),
                              ),
                              const Gap(8),
                              Text(
                                translatePitchType(
                                  pitch.pitchType.pitchType,
                                ),
                                style: tablePitchNameStyle,
                                maxLines: 2,
                              ),
                            ],
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            UnitConverter.formatVelocity(
                              pitch.stats.initialVelocity,
                              unitType,
                            ).value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            UnitConverter.formatBreak(
                              pitch.stats.verticalBreak,
                              unitType,
                            ).value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                        Expanded(
                          flex: 1,
                          child: Text(
                            UnitConverter.formatBreak(
                              pitch.stats.horizontalBreak,
                              unitType,
                            ).value,
                            textAlign: TextAlign.right,
                            style: tableValueStyle,
                          ),
                        ),
                      ],
                    ),
                  );
                }),
              ],
            ),
          ),
        ],
      ),
      children: [
        for (var i = 0; i < pitches.length; i++)
          CardSurface(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      Container(
                        width: 6,
                        height: 24,
                        color: getPitchTypeColor(
                          pitches[i].pitchType.pitchType,
                        ),
                      ),
                      const Gap(8),
                      Text(
                        translatePitchType(
                          pitches[i].pitchType.pitchType,
                        ),
                        style: pitchNameStyle,
                      ),
                    ],
                  ),
                  const Gap(8),
                  Table(
                    columnWidths: const {
                      0: FlexColumnWidth(1),
                      1: FlexColumnWidth(2),
                    },
                    children: [
                      TableRow(
                        children: [
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              'velo',
                              style: detailLabelStyle,
                            ),
                          ),
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              () {
                                final v = UnitConverter.formatVelocity(
                                  pitches[i].stats.initialVelocity,
                                  unitType,
                                );
                                return '${v.value} ${v.unit}';
                              }(),
                              style: detailLabelStyle,
                              textAlign: TextAlign.right,
                            ),
                          ),
                        ],
                      ),
                      TableRow(
                        children: [
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              'vb',
                              style: detailLabelStyle,
                            ),
                          ),
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              () {
                                final vb = UnitConverter.formatBreak(
                                  pitches[i].stats.verticalBreak,
                                  unitType,
                                );
                                return '${vb.value} ${vb.unit}';
                              }(),
                              style: detailLabelStyle,
                              textAlign: TextAlign.right,
                            ),
                          ),
                        ],
                      ),
                      TableRow(
                        children: [
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              'hb',
                              style: detailLabelStyle,
                            ),
                          ),
                          Padding(
                            padding: const EdgeInsets.only(bottom: 4.0),
                            child: Text(
                              () {
                                final hb = UnitConverter.formatBreak(
                                  pitches[i].stats.horizontalBreak,
                                  unitType,
                                );
                                return '${hb.value} ${hb.unit}';
                              }(),
                              style: detailLabelStyle,
                              textAlign: TextAlign.right,
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                  const Gap(8),
                  for (final note in pitches[i].notes)
                    Padding(
                      padding: const EdgeInsets.symmetric(vertical: 2),
                      child: Text(
                        '• $note',
                        style: detailLabelStyle,
                      ),
                    ),
                ],
              ),
            ),
          ),
        // トンネル候補
        if (pitchFeatures.tunnelCandidates.goodTunnels.isNotEmpty) ...[
          SectionTitle(l10n.ai_coach_report__tunnel_candidates_title),
          const Gap(8),
          StrategyList(
            items: pitchFeatures.tunnelCandidates.goodTunnels
                .map((e) => (e.label, e.description))
                .toList(),
            background: const Color(0xFFF5F9FF),
            borderLeft: const Color(0xFF42A5F5),
          ),
        ],
      ],
    );
  }
}
